import { NextRequest, NextResponse } from 'next/server';
import crypto from 'crypto';

/**
 * POST /api/razorpay/webhook
 * Handles Razorpay webhook events
 * 
 * Webhook events:
 * - payment.authorized
 * - payment.failed
 * - payment.captured
 * - refund.created
 * - refund.failed
 */
export async function POST(request: NextRequest) {
  try {
    const body = await request.text();
    const signature = request.headers.get('x-razorpay-signature');

    if (!signature) {
      return NextResponse.json(
        { error: 'Missing signature header' },
        { status: 400 }
      );
    }

    // Verify webhook signature
    const webhookSecret = process.env.RAZORPAY_WEBHOOK_SECRET;
    if (!webhookSecret) {
      console.error('Webhook secret not configured');
      return NextResponse.json(
        { error: 'Webhook secret not configured' },
        { status: 500 }
      );
    }

    const expectedSignature = crypto
      .createHmac('sha256', webhookSecret)
      .update(body)
      .digest('hex');

    if (expectedSignature !== signature) {
      console.error('Invalid webhook signature');
      return NextResponse.json(
        { error: 'Invalid signature' },
        { status: 400 }
      );
    }

    // Parse webhook payload
    const event = JSON.parse(body);
    const eventType = event.event;
    const eventData = event.payload;

    console.log(`Processing webhook event: ${eventType}`, eventData);

    // Handle different webhook events
    switch (eventType) {
      case 'payment.authorized':
        await handlePaymentAuthorized(eventData);
        break;

      case 'payment.failed':
        await handlePaymentFailed(eventData);
        break;

      case 'payment.captured':
        await handlePaymentCaptured(eventData);
        break;

      case 'refund.created':
        await handleRefundCreated(eventData);
        break;

      case 'refund.failed':
        await handleRefundFailed(eventData);
        break;

      default:
        console.log(`Unhandled webhook event: ${eventType}`);
    }

    // Return success response to Razorpay
    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Error processing webhook:', error);

    return NextResponse.json(
      {
        error: 'Failed to process webhook',
        details: error instanceof Error ? error.message : 'Unknown error',
      },
      { status: 500 }
    );
  }
}

